#include <threads.h>
#include <hardware.h>
#include <terminals.h>

#ifndef TERMINAL_MAX_LINE
#define TERMINAL_MAX_LINE 1024
#endif

#ifndef ERROR
#define ERROR (-1)
#endif

#define INPUT_BUF_SIZE 4096
#define ECHO_BUF_SIZE  4096

/*
 * Per-terminal state.  All fields are private to this monitor.
 */
static struct {
    int initialized;

    /* Input buffer (circular) — holds completed lines + current editing line */
    char input_buf[INPUT_BUF_SIZE];
    int  input_head;
    int  input_tail;
    int  input_count;
    int  input_lines;      /* number of complete lines (\n) in buffer */
    int  editing_count;    /* chars in current incomplete line (for backspace) */

    /* Echo buffer (circular) — chars waiting to be echoed to terminal */
    char echo_buf[ECHO_BUF_SIZE];
    int  echo_head;
    int  echo_tail;
    int  echo_count;

    /* WriteTerminal state */
    char *write_buf;
    int   write_len;
    int   write_pos;
    int   write_expanding;  /* mid \n -> \r\n expansion */
    int   write_busy;       /* a WriteTerminal is in progress */

    /* Hardware transmit state */
    int transmitting;

    /* Statistics */
    struct termstat stats;

    /* Condition variables */
    cond_id_t read_cv;        /* reader waits for a complete input line */
    cond_id_t write_done_cv;  /* writer waits for all chars transmitted */
    cond_id_t write_avail_cv; /* writer waits for exclusive write access */
} terms[NUM_TERMINALS];

static int driver_init = 0;

/* ----------------------------------------------------------------
 * Internal (non-entry) helpers — declared static so they cannot be
 * called from outside this monitor.
 * ---------------------------------------------------------------- */

static void
echo_enq(int t, char c)
{
    if (terms[t].echo_count < ECHO_BUF_SIZE) {
        terms[t].echo_buf[terms[t].echo_tail] = c;
        terms[t].echo_tail = (terms[t].echo_tail + 1) % ECHO_BUF_SIZE;
        terms[t].echo_count++;
    }
}

static void
input_enq(int t, char c)
{
    if (terms[t].input_count < INPUT_BUF_SIZE) {
        terms[t].input_buf[terms[t].input_tail] = c;
        terms[t].input_tail = (terms[t].input_tail + 1) % INPUT_BUF_SIZE;
        terms[t].input_count++;
    }
}

/*
 * Try to transmit the next pending character to the terminal hardware.
 * Echo output always has priority over WriteTerminal output.
 */
static void
do_transmit(int t)
{
    char c;

    if (terms[t].transmitting)
        return;

    /* Priority 1: echo output */
    if (terms[t].echo_count > 0) {
        c = terms[t].echo_buf[terms[t].echo_head];
        terms[t].echo_head = (terms[t].echo_head + 1) % ECHO_BUF_SIZE;
        terms[t].echo_count--;
        WriteDataRegister(t, c);
        terms[t].stats.tty_out++;
        terms[t].transmitting = 1;
        return;
    }

    /* Priority 2: WriteTerminal output */
    if (terms[t].write_busy) {
        /* Finish \r\n expansion: send the \n half */
        if (terms[t].write_expanding) {
            WriteDataRegister(t, '\n');
            terms[t].stats.tty_out++;
            terms[t].transmitting = 1;
            terms[t].write_expanding = 0;
            terms[t].write_pos++;
            if (terms[t].write_pos >= terms[t].write_len)
                CondSignal(terms[t].write_done_cv);
            return;
        }
        if (terms[t].write_pos < terms[t].write_len) {
            c = terms[t].write_buf[terms[t].write_pos];
            if (c == '\n') {
                /* Start \r\n expansion: send \r now, \n next */
                WriteDataRegister(t, '\r');
                terms[t].stats.tty_out++;
                terms[t].transmitting = 1;
                terms[t].write_expanding = 1;
            } else {
                WriteDataRegister(t, c);
                terms[t].stats.tty_out++;
                terms[t].transmitting = 1;
                terms[t].write_pos++;
                if (terms[t].write_pos >= terms[t].write_len)
                    CondSignal(terms[t].write_done_cv);
            }
        }
    }
}

/* ================================================================
 * Monitor entry procedures (Sections 6.1 and 6.2)
 * ================================================================ */

extern int
InitTerminalDriver(void)
{
    int i;
    Declare_Monitor_Entry_Procedure();

    if (driver_init)
        return ERROR;

    for (i = 0; i < NUM_TERMINALS; i++) {
        terms[i].initialized    = 0;
        terms[i].input_head     = 0;
        terms[i].input_tail     = 0;
        terms[i].input_count    = 0;
        terms[i].input_lines    = 0;
        terms[i].editing_count  = 0;
        terms[i].echo_head      = 0;
        terms[i].echo_tail      = 0;
        terms[i].echo_count     = 0;
        terms[i].write_buf      = 0;
        terms[i].write_len      = 0;
        terms[i].write_pos      = 0;
        terms[i].write_expanding = 0;
        terms[i].write_busy     = 0;
        terms[i].transmitting   = 0;
        terms[i].stats.tty_in   = -1;
        terms[i].stats.tty_out  = -1;
        terms[i].stats.user_in  = -1;
        terms[i].stats.user_out = -1;
        terms[i].read_cv        = CondCreate();
        terms[i].write_done_cv  = CondCreate();
        terms[i].write_avail_cv = CondCreate();
    }

    driver_init = 1;
    return 0;
}

extern int
InitTerminal(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_init)
        return ERROR;
    if (term < 0 || term >= NUM_TERMINALS)
        return ERROR;
    if (terms[term].initialized)
        return ERROR;

    if (InitHardware(term) != 0)
        return ERROR;

    terms[term].initialized    = 1;
    terms[term].stats.tty_in   = 0;
    terms[term].stats.tty_out  = 0;
    terms[term].stats.user_in  = 0;
    terms[term].stats.user_out = 0;

    return 0;
}

extern int
WriteTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_init)
        return ERROR;
    if (term < 0 || term >= NUM_TERMINALS)
        return ERROR;
    if (!terms[term].initialized)
        return ERROR;
    if (buflen < 0)
        return ERROR;
    if (buflen == 0)
        return 0;
    if (!buf)
        return ERROR;

    /* Count user chars received from user */
    terms[term].stats.user_in += buflen;

    /* Serialize concurrent writers on this terminal */
    while (terms[term].write_busy)
        CondWait(terms[term].write_avail_cv);

    terms[term].write_busy      = 1;
    terms[term].write_buf       = buf;
    terms[term].write_len       = buflen;
    terms[term].write_pos       = 0;
    terms[term].write_expanding = 0;

    /* Kick off transmission if hardware is idle */
    do_transmit(term);

    /* Block until all characters have been written */
    while (terms[term].write_pos < terms[term].write_len ||
           terms[term].write_expanding)
        CondWait(terms[term].write_done_cv);

    terms[term].write_busy = 0;
    terms[term].write_buf  = 0;
    CondSignal(terms[term].write_avail_cv);

    return buflen;
}

extern int
ReadTerminal(int term, char *buf, int buflen)
{
    int n;
    char c;
    Declare_Monitor_Entry_Procedure();

    if (!driver_init)
        return ERROR;
    if (term < 0 || term >= NUM_TERMINALS)
        return ERROR;
    if (!terms[term].initialized)
        return ERROR;
    if (buflen < 0)
        return ERROR;
    if (buflen == 0)
        return 0;
    if (!buf)
        return ERROR;

    /* Wait until a complete line is available */
    while (terms[term].input_lines == 0)
        CondWait(terms[term].read_cv);

    /* Copy characters from input buffer into user buffer */
    n = 0;
    while (n < buflen && terms[term].input_count > 0) {
        c = terms[term].input_buf[terms[term].input_head];
        buf[n++] = c;
        terms[term].input_head =
            (terms[term].input_head + 1) % INPUT_BUF_SIZE;
        terms[term].input_count--;
        if (c == '\n') {
            terms[term].input_lines--;
            break;
        }
    }

    terms[term].stats.user_out += n;

    /* Wake another waiting reader if more complete lines remain */
    if (terms[term].input_lines > 0)
        CondSignal(terms[term].read_cv);

    return n;
}

extern int
TerminalDriverStatistics(struct termstat *stats)
{
    int i;
    Declare_Monitor_Entry_Procedure();

    if (!driver_init)
        return ERROR;
    if (!stats)
        return ERROR;

    for (i = 0; i < NUM_TERMINALS; i++)
        stats[i] = terms[i].stats;

    return 0;
}

extern void
ReceiveInterrupt(int term)
{
    char c;
    Declare_Monitor_Entry_Procedure();

    if (term < 0 || term >= NUM_TERMINALS || !terms[term].initialized)
        return;

    c = ReadDataRegister(term);
    terms[term].stats.tty_in++;

    if (c == '\r' || c == '\n') {
        /* Echo \r\n, store \n, complete a line */
        echo_enq(term, '\r');
        echo_enq(term, '\n');
        input_enq(term, '\n');
        terms[term].input_lines++;
        terms[term].editing_count = 0;
        CondSignal(terms[term].read_cv);
    } else if (c == '\b' || c == '\177') {
        /* Backspace / delete: erase last char of current editing line */
        if (terms[term].editing_count > 0) {
            terms[term].input_tail =
                (terms[term].input_tail - 1 + INPUT_BUF_SIZE) % INPUT_BUF_SIZE;
            terms[term].input_count--;
            terms[term].editing_count--;
            echo_enq(term, '\b');
            echo_enq(term, ' ');
            echo_enq(term, '\b');
        }
    } else {
        /* Regular character: store and echo if buffer not full */
        if (terms[term].input_count < TERMINAL_MAX_LINE) {
            input_enq(term, c);
            terms[term].editing_count++;
            echo_enq(term, c);
        }
        /* Buffer full: drop character silently */
    }

    /* Start transmitting echo chars if hardware is idle */
    do_transmit(term);
}

extern void
TransmitInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (term < 0 || term >= NUM_TERMINALS || !terms[term].initialized)
        return;

    terms[term].transmitting = 0;
    do_transmit(term);
}

